mapper.select:
SELECT u.id AS user_id, u.nickname, u.avatar, CONCAT(IFNULL(u.country, ''), ' ', IFNULL(u.province, '')) AS ip_location, u.create_time, u.personal_intro, IFNULL(us.total_views, 0) AS total_views, IFNULL(us.total_articles, 0) AS total_articles, IFNULL(us.follower_count, 0) AS follower_count, IFNULL(us.follow_count, 0) AS follow_count, CASE WHEN uf.id IS NOT NULL AND uf.is_cancel = 0 THEN 1 ELSE 0 END AS is_followed, CASE WHEN ufr.id IS NOT NULL AND DATE(ufr.request_time) = CURDATE() THEN 1 ELSE 0 END AS is_requested_update, IFNULL(us.total_likes, 0) AS total_likes, IFNULL(us.total_comments, 0) AS total_comments, IFNULL(us.total_collects, 0) AS total_collects, IFNULL(us.total_shares, 0) AS total_shares FROM t_user u LEFT JOIN t_user_stat us ON u.id = us.user_id
LEFT JOIN t_user_follow uf ON u.id = uf.followed_user_id AND uf.user_id = #{currentUserId} AND uf.is_cancel = 0 LEFT JOIN t_user_follow_request ufr ON u.id = ufr.followed_user_id AND ufr.user_id = #{currentUserId}
WHERE u.id = #{userId} AND u.status = 1
